import { unstable_cache } from 'next/cache';
import { getAllProducts } from '@/lib/db';

/**
 * Returns product catalog data, cached with the "products" cache tag.
 *
 * Every cached reader that depends on this tag stays in sync: calling
 * revalidateTag("products") anywhere (e.g. from a sync action) causes
 * the next request to any tagged consumer to re-fetch fresh data.
 */
export const getCachedProducts = unstable_cache(
  async () => getAllProducts(),
  ['catalog-products-list'],
  { tags: ['products'] },
);

import type { Metadata } from 'next';

export const metadata: Metadata = {
  title: 'Admin – Catalog',
};

export default function AdminLayout({
  children,
}: Readonly<{
  children: React.ReactNode;
}>) {
  return (
    <div style={{ fontFamily: 'system-ui, sans-serif', padding: '2rem' }}>
      <header style={{ marginBottom: '2rem' }}>
        <a
          href="/admin/catalog"
          style={{
            fontSize: '1.5rem',
            fontWeight: 700,
            color: '#111',
            textDecoration: 'none',
          }}
        >
          ⚙️ Admin
        </a>
        <nav style={{ marginTop: '0.5rem', display: 'flex', gap: '1rem' }}>
          <a href="/admin/catalog" style={{ color: '#2563eb', fontWeight: 500 }}>
            Product Catalog
          </a>
          <a href="/" style={{ color: '#666' }}>
            ← Back to storefront
          </a>
        </nav>
      </header>
      {children}
    </div>
  );
}

import { Suspense } from 'react';
import { revalidateTag } from 'next/cache';
import { getCachedProducts } from '@/lib/catalog';

/* ------------------------------------------------------------------ */
/*  Inline Server Action                                               */
/* ------------------------------------------------------------------ */

async function syncCatalog() {
  'use server';

  // Invalidate every data-fetch cache entry tagged "products".
  // Downstream views that read cached data with the same tag will
  // pick up the freshest data on their next request — no blocking.
  revalidateTag('products');
}

/* ------------------------------------------------------------------ */
/*  Page Component                                                     */
/* ------------------------------------------------------------------ */

export default function CatalogPage() {
  return (
    <Suspense fallback={<CatalogSkeleton />}>
      <CatalogContent />
    </Suspense>
  );
}

/* ------------------------------------------------------------------ */
/*  Inner content (async, reads cached product data)                   */
/* ------------------------------------------------------------------ */

async function CatalogContent() {
  const products = await getCachedProducts();

  const syncedAt = new Date().toLocaleString('en-US', {
    month: 'short',
    day: 'numeric',
    year: 'numeric',
    hour: '2-digit',
    minute: '2-digit',
    second: '2-digit',
  });

  return (
    <div>
      {/* ---- header row ---- */}
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          marginBottom: '1.5rem',
          flexWrap: 'wrap',
          gap: '1rem',
        }}
      >
        <div>
          <h1 style={{ fontSize: '1.25rem', fontWeight: 600, margin: 0 }}>
            Product Catalog
          </h1>
          <p style={{ color: '#666', fontSize: '0.875rem', margin: '0.25rem 0 0' }}>
            {products.length} products &middot; viewed {syncedAt}
          </p>
        </div>

        <form action={syncCatalog}>
          <button
            type="submit"
            style={{
              padding: '0.5rem 1rem',
              fontSize: '0.875rem',
              fontWeight: 500,
              color: '#fff',
              backgroundColor: '#2563eb',
              border: 'none',
              borderRadius: '6px',
              cursor: 'pointer',
              whiteSpace: 'nowrap',
            }}
          >
            ↻ Sync latest catalog
          </button>
        </form>
      </div>

      {/* ---- Sync info banner ---- */}
      <div
        style={{
          padding: '0.75rem 1rem',
          marginBottom: '1rem',
          fontSize: '0.8125rem',
          color: '#6b21a8',
          backgroundColor: '#f3e8ff',
          borderRadius: '6px',
          lineHeight: 1.5,
        }}
      >
        ⚡ Catalog data is cached for fast browsing.
        {/*  TODO: wire to live ERP/PIM webhook  */}
        Use <strong>Sync latest catalog</strong> to refresh after upstream
        pricing, inventory, or availability changes. Data refreshes in the
        background — other catalog views pick up the update on their next load.
      </div>

      {/* ---- Product table ---- */}
      <div style={{ overflowX: 'auto' }}>
        <table
          style={{
            width: '100%',
            borderCollapse: 'collapse',
            fontSize: '0.875rem',
          }}
        >
          <thead>
            <tr style={{ textAlign: 'left', borderBottom: '2px solid #e5e7eb' }}>
              <Th>SKU</Th>
              <Th>Name</Th>
              <Th>Category</Th>
              <Th style={{ textAlign: 'right' }}>Price</Th>
              <Th style={{ textAlign: 'right' }}>Inventory</Th>
              <Th>Availability</Th>
            </tr>
          </thead>
          <tbody>
            {products.map((product) => (
              <tr
                key={product.id}
                style={{ borderBottom: '1px solid #e5e7eb' }}
              >
                <Td>
                  <code style={{ fontSize: '0.8125rem', color: '#666' }}>
                    {product.sku}
                  </code>
                </Td>
                <Td>{product.name}</Td>
                <Td>{product.category}</Td>
                <Td style={{ textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
                  ${product.price.toLocaleString()}
                </Td>
                <Td style={{ textAlign: 'right', fontVariantNumeric: 'tabular-nums' }}>
                  <span style={{ color: product.inventory === 0 ? '#dc2626' : '#111' }}>
                    {product.inventory}
                  </span>
                </Td>
                <Td>
                  {product.available ? (
                    <span style={badgeSuccess}>In Stock</span>
                  ) : (
                    <span style={badgeDanger}>Out of Stock</span>
                  )}
                </Td>
              </tr>
            ))}
          </tbody>
        </table>
      </div>

      {/* ---- Footer note ---- */}
      <p
        style={{
          marginTop: '1.5rem',
          fontSize: '0.75rem',
          color: '#9ca3af',
          textAlign: 'center',
        }}
      >
        Cache tag: <code style={{ background: '#f3f4f6', padding: '0 0.25rem' }}>products</code>
        {' — '}
        <code>revalidateTag(&quot;products&quot;)</code> is called on sync
      </p>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Loading skeleton (renders while Suspense boundary is pending)      */
/* ------------------------------------------------------------------ */

function CatalogSkeleton() {
  return (
    <div>
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          marginBottom: '1.5rem',
        }}
      >
        <div>
          <div
            style={{
              width: '200px',
              height: '1.25rem',
              background: '#e5e7eb',
              borderRadius: '4px',
              marginBottom: '0.5rem',
            }}
          />
          <div
            style={{
              width: '120px',
              height: '0.875rem',
              background: '#e5e7eb',
              borderRadius: '4px',
            }}
          />
        </div>
        <div
          style={{
            width: '160px',
            height: '2rem',
            background: '#e5e7eb',
            borderRadius: '6px',
          }}
        />
      </div>
      <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
        {Array.from({ length: 5 }).map((_, i) => (
          <div
            key={i}
            style={{
              width: '100%',
              height: '2.5rem',
              background: '#f3f4f6',
              borderRadius: '4px',
            }}
          />
        ))}
      </div>
    </div>
  );
}

/* ------------------------------------------------------------------ */
/*  Styled table helpers                                               */
/* ------------------------------------------------------------------ */

function Th(
  props: React.ThHTMLAttributes<HTMLTableCellElement> & { children: React.ReactNode },
) {
  return (
    <th
      {...props}
      style={{
        padding: '0.75rem 0.75rem 0.5rem',
        fontWeight: 600,
        color: '#374151',
        fontSize: '0.75rem',
        textTransform: 'uppercase',
        letterSpacing: '0.05em',
        ...(props.style as React.CSSProperties | undefined),
      }}
    />
  );
}

function Td(
  props: React.TdHTMLAttributes<HTMLTableCellElement> & { children: React.ReactNode },
) {
  return (
    <td
      {...props}
      style={{
        padding: '0.75rem',
        color: '#111',
        ...(props.style as React.CSSProperties | undefined),
      }}
    />
  );
}

/* ------------------------------------------------------------------ */
/*  Badge styles                                                       */
/* ------------------------------------------------------------------ */

const badgeSuccess: React.CSSProperties = {
  display: 'inline-block',
  padding: '0.125rem 0.5rem',
  fontSize: '0.75rem',
  fontWeight: 500,
  color: '#166534',
  backgroundColor: '#dcfce7',
  borderRadius: '999px',
};

const badgeDanger: React.CSSProperties = {
  display: 'inline-block',
  padding: '0.125rem 0.5rem',
  fontSize: '0.75rem',
  fontWeight: 500,
  color: '#991b1b',
  backgroundColor: '#fef2f2',
  borderRadius: '999px',
};

export default function CatalogLoading() {
  return (
    <div>
      {/* ---- skeleton header row ---- */}
      <div
        style={{
          display: 'flex',
          justifyContent: 'space-between',
          alignItems: 'flex-start',
          marginBottom: '1.5rem',
        }}
      >
        <div>
          <div
            style={{
              width: '200px',
              height: '1.25rem',
              background: '#e5e7eb',
              borderRadius: '4px',
              marginBottom: '0.5rem',
            }}
          />
          <div
            style={{
              width: '120px',
              height: '0.875rem',
              background: '#e5e7eb',
              borderRadius: '4px',
            }}
          />
        </div>
        <div
          style={{
            width: '160px',
            height: '2rem',
            background: '#e5e7eb',
            borderRadius: '6px',
          }}
        />
      </div>

      {/* ---- skeleton info banner ---- */}
      <div
        style={{
          width: '100%',
          height: '2.5rem',
          background: '#e5e7eb',
          borderRadius: '6px',
          marginBottom: '1rem',
        }}
      />

      {/* ---- skeleton table rows ---- */}
      <div style={{ display: 'flex', flexDirection: 'column', gap: '0.5rem' }}>
        {/* header */}
        <div
          style={{
            width: '100%',
            height: '2.5rem',
            background: '#f3f4f6',
            borderRadius: '4px',
          }}
        />
        {Array.from({ length: 6 }).map((_, i) => (
          <div
            key={i}
            style={{
              width: '100%',
              height: '2.5rem',
              background: '#f9fafb',
              borderRadius: '4px',
            }}
          />
        ))}
      </div>
    </div>
  );
}

'use client';

export default function CatalogError({
  error,
  reset,
}: {
  error: Error & { digest?: string };
  reset: () => void;
}) {
  return (
    <div
      style={{
        padding: '3rem 1rem',
        textAlign: 'center',
        fontFamily: 'system-ui, sans-serif',
      }}
    >
      <div
        style={{
          display: 'inline-flex',
          alignItems: 'center',
          justifyContent: 'center',
          width: '3rem',
          height: '3rem',
          borderRadius: '999px',
          background: '#fef2f2',
          color: '#dc2626',
          fontSize: '1.5rem',
          marginBottom: '1rem',
        }}
      >
        !
      </div>
      <h2
        style={{
          fontSize: '1.125rem',
          fontWeight: 600,
          color: '#111',
          margin: '0 0 0.5rem',
        }}
      >
        Failed to load catalog
      </h2>
      <p style={{ color: '#666', fontSize: '0.875rem', maxWidth: '400px', margin: '0 auto 1.5rem' }}>
        {error.message || 'An unexpected error occurred while loading the product catalog.'}
      </p>
      <button
        onClick={reset}
        style={{
          padding: '0.5rem 1.25rem',
          fontSize: '0.875rem',
          fontWeight: 500,
          color: '#fff',
          backgroundColor: '#2563eb',
          border: 'none',
          borderRadius: '6px',
          cursor: 'pointer',
        }}
      >
        Try again
      </button>
    </div>
  );
}

