import { Suspense } from 'react';
import { revalidateTag } from 'next/cache';
import { getCachedProducts } from '@/lib/catalog';

/* ------------------------------------------------------------------ */
/*  Inline Server Action                                               */
/* ------------------------------------------------------------------ */

async function syncCatalog() {
  'use server';

  // Invalidate every data-fetch cache entry tagged "products".
  // Downstream views that read cached data with the same tag will
  // pick up the freshest data on their next request — no blocking.
  // The "max" profile is required in this Next.js version and keeps
  // the entry's expiry unchanged (never), matching the deprecation
  // guidance: https://nextjs.org/docs/messages/revalidate-tag-single-arg
  revalidateTag('products', 'max');
}
